import { ChatOpenAI } from "@langchain/openai";
import { ChatPromptTemplate } from "@langchain/core/prompts";
import { StringOutputParser } from "@langchain/core/output_parsers";

const llm = new ChatOpenAI({ model: "gpt-4o-mini", temperature: 0.7 });

const prompt = ChatPromptTemplate.fromTemplate(
  `Write for {brand}: {brandVoice}

Topic: {topic}

Include SEO keywords: {keywords}

{length} article:`
);

const chain = prompt.pipe(llm).pipe(new StringOutputParser());

const result = await chain.invoke({
  brand: "VexAI",
  brandVoice: "Technical, authoritative, future-focused",
  topic: "LLM Guardrails",
  keywords: "ai reliability, llm safety, agent monitoring",
  length: "1200 words"
});

console.log(result);

from langgraph.prebuilt import create_react_agent

from langchain_core.tools import tool


@tool
def keyword_research(topic: str) -> str:
    """Generate SEO keywords for content topic"""
    return f"Primary: {topic.replace(' ', '-')}, Secondary: ai, llm, reliability"


@tool
def plagiarism_check(content: str) -> str:
    """Check content originality"""
    return "99% original - minor common phrases detected"


content_agent = create_react_agent(llm, [keyword_research, plagiarism_check]);

agent_result = content_agent.invoke({
    "messages": [("user", "Write blog post about LangChain content safety. Research first.")]
});

