import { Vex } from "vex-sdk";
import { ChatOpenAI, StringOutputParser } from "@langchain/openai";

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  project: "content-generation"
});

const llm = new ChatOpenAI({ model: "gpt-4o-mini" });
const chain = prompt.pipe(llm).pipe(new StringOutputParser());

// Create verifier for brand + SEO
const verifier = await vex.verifier({
  name: "brand-content",
  checks: [
    {
      type: "brand_voice",
      model: "vex-corporate-v1",
      threshold: 0.88
    },
    {
      type: "seo_compliance",
      keywords: ["llm", "ai reliability", "content safety"],
      density: 0.02
    },
    "factual_accuracy"
  ]
});

// Verified execution
const result = await verifier.verify(chain.invoke.bind(chain), {
  topic: "LangChain Content Generation",
  brand: "VexAI"
});

if (result.passed) {
  console.log("✅ Published:", result.output);
} else {
  console.error("❌ Blocked:", result.failures);
}
